mapper.select:
SELECT s.*, m.name AS merchantName, m.contact_phone
FROM services s
LEFT JOIN service_merchant m ON s.merchant_id = m.id
WHERE s.deleted = 0
  AND s.audit_status != 3

    AND s.name LIKE CONCAT('%', #{parm.name}, '%')


    AND s.category_id = #{parm.categoryId}


    AND s.status = #{parm.status}


    AND s.audit_status = #{parm.auditStatus}

ORDER BY s.create_time DESC
